import{_ as o,o as t,c as i,a2 as a}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"RFC 0014 — Minimal shell mode","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0014-minimal-shell-mode.md","filePath":"rfcs/0014-minimal-shell-mode.md"}'),n={name:"rfcs/0014-minimal-shell-mode.md"};function s(r,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-0014-—-minimal-shell-mode" tabindex="-1">RFC 0014 — Minimal shell mode <a class="header-anchor" href="#rfc-0014-—-minimal-shell-mode" aria-label="Permalink to &quot;RFC 0014 — Minimal shell mode&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>scripts/generate-registry.ts</code> (composition), runtime route tree (a new <code>(minimal)</code> route group + committed layout + <code>.gitignore</code>), <code>runtime/src/root-plugin.ts</code> (eligibility), <code>packages/manifest</code> (validation), <code>docs/plugin-development.md</code>, CLAUDE.md, SRS; builds on RFC 0001 (shell modes) and RFC 0013 (mobile responsiveness)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.5.25; documentation-first. This RFC specifies the wiring and the remaining missing pieces for <code>shell: &quot;minimal&quot;</code>; SRS requirement IDs, scheduling, and task allocation are deferred.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Wire the third manifest <code>shell</code> mode — <strong><code>minimal</code></strong> — which is declared in the schema but currently <strong>fails the build</strong>. A <code>minimal</code> plugin renders with <strong>no platform chrome</strong>: no sidebar, header, footer, or overlay slot. The plugin owns the <strong>entire viewport</strong>, for full-bleed experiences (an editor, a canvas, a presentation/kiosk surface).</p><p>The mechanism mirrors the existing route-composition model: a <code>minimal</code> plugin composes into a <strong>new top-level <code>(minimal)</code> route group</strong> that is a <strong>sibling</strong> of <code>(platform)</code> — so it escapes the shell layout — while remaining session-gated by the middleware exactly like every other route (the gate is path-based and route-group-agnostic). This RFC defines that group, the generate-script branch that replaces the build-fail, root-plugin eligibility, the navigation contract, and the docs/tests that complete the mode.</p><p>It honours the <strong>responsive expectations</strong> RFC 0013 sets for minimal (full <code>dvh</code> height, <code>viewport-fit=cover</code>, safe-area pass-through, no chrome).</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p><code>shell: &quot;minimal&quot;</code> has been a declared-but-unimplemented enum value since RFC 0001. The generate script intentionally <strong>fails loudly</strong> rather than mis-composing one:</p><blockquote><p><code>[generate] plugin &lt;id&gt; declares shell: &quot;minimal&quot;, which is not yet supported — a chrome-free route group lands with the first minimal plugin.</code> — <code>scripts/generate-registry.ts:138–144</code></p></blockquote><p>That placeholder has done its job (no silent breakage), but it blocks a whole class of legitimate plugins: a writing surface like Plainwrite, a drawing canvas, a slideshow, or a single-purpose kiosk deployment, all of which want the screen to themselves. Completing <code>minimal</code> closes the last gap in the shell-mode trio (<code>default</code> ✅, <code>overlay</code> ✅, <code>minimal</code> ⏳) and is almost entirely <strong>our own route-composition code</strong> — low-ambiguity, low-risk wiring.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Shell mode drives composition, not request-time branching.</strong> The generate script picks a destination from the manifest <code>shell</code> so the plugin inherits the right layout from the route tree (<code>scripts/generate-registry.ts:15–28, 124–161</code>): <ul><li><code>default</code> → <code>runtime/app/(platform)/(plugins)/&lt;routePrefix&gt;/</code> (under the shell);</li><li><code>overlay</code> → the fallback <strong>and</strong> the <code>@modal/(.)&lt;segment&gt;</code> interception copy;</li><li><code>minimal</code> → <strong><code>process.exit(1)</code></strong> (the build-fail above).</li></ul></li><li><strong>Chrome lives in one layout.</strong> <code>runtime/app/(platform)/layout.tsx</code> renders the sidebar + mobile header/footer and reads <code>headers()</code> (making it dynamic). Any route group <strong>nested under <code>(platform)</code></strong> inherits this chrome — so a chrome-free plugin <strong>cannot</strong> live under <code>(platform)</code>; it needs a sibling group.</li><li><strong><code>(plugins)/layout.tsx</code> is a pass-through</strong> that exists only to host the <code>@modal</code> slot (<code>runtime/app/(platform)/(plugins)/layout.tsx</code>) — it adds no chrome, but it still sits inside <code>(platform)</code>, so it is not the escape hatch either.</li><li><strong>The middleware gates by URL path, not route group.</strong> Its matcher excludes only auth/PWA/static paths and gates everything else (<code>runtime/middleware.ts:220–228</code>); <code>decidePluginRoute</code> enforces <code>adminOnly</code> (403) and disabled (404) by <code>routePrefix</code> (<code>:174–187</code>); <code>/</code> rewrites to the root plugin&#39;s prefix (<code>:206–215</code>). <strong>None of this depends on which route group a plugin composes into</strong> — a <code>minimal</code> plugin at <code>/editor</code> is gated identically whether it lives in <code>(platform)</code> or <code>(minimal)</code>.</li><li><strong>The root layout owns the document.</strong> <code>runtime/app/layout.tsx</code> provides <code>&lt;html&gt;/&lt;body&gt;</code>, the <code>--sv-*</code> tokens, the pre-paint theme script, and the viewport metadata. Both <code>(platform)</code> and a new <code>(minimal)</code> group nest under it, so a minimal plugin inherits theme + tokens + (RFC 0013) <code>viewport-fit=cover</code> with <strong>no extra work</strong>.</li><li><strong>Root-plugin eligibility</strong> currently rejects only <code>overlay</code> (<code>runtime/src/root-plugin.ts:22</code>); <code>minimal</code> is, by omission, already eligible.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="a-new-minimal-route-group-sibling-of-platform" tabindex="-1">A new <code>(minimal)</code> route group (sibling of <code>(platform)</code>) <a class="header-anchor" href="#a-new-minimal-route-group-sibling-of-platform" aria-label="Permalink to &quot;A new `(minimal)` route group (sibling of `(platform)`)&quot;">​</a></h3><p>Add <code>runtime/app/(minimal)/</code> as a <strong>top-level, URL-transparent</strong> route group alongside <code>(platform)</code>. Because route groups don&#39;t affect the URL, a plugin with <code>routePrefix: /editor</code> composed at <code>runtime/app/(minimal)/editor/</code> still serves at <code>/editor</code> and is still middleware-gated — it simply does <strong>not</strong> inherit the shell chrome.</p><p>Committed (hand-written) files in the group, mirroring the <code>(plugins)</code> pattern:</p><ul><li><strong><code>(minimal)/layout.tsx</code></strong> — chrome-free. Renders <code>{children}</code> full-bleed (a <code>100dvh</code> container honouring <code>env(safe-area-inset-*)</code> per RFC 0013), and forces <strong>dynamic rendering</strong> (await <code>headers()</code> or <code>export const dynamic = &#39;force-dynamic&#39;</code>) so the per-request CSP nonce applies to any inline scripts — the same reason <code>(platform)/layout.tsx</code> is dynamic and <code>apps/auth</code> forces dynamic (RFC 0008). No sidebar/header/footer, no <code>@modal</code> slot.</li><li><strong><code>(minimal)/.gitignore</code></strong> — keeps the committed <code>layout.tsx</code> + <code>.gitignore</code>, ignores the generated composed copies (the same allowlist approach the <code>(plugins)/.gitignore</code> uses).</li></ul><h3 id="generate-script-branch-replace-the-build-fail" tabindex="-1">Generate-script branch (replace the build-fail) <a class="header-anchor" href="#generate-script-branch-replace-the-build-fail" aria-label="Permalink to &quot;Generate-script branch (replace the build-fail)&quot;">​</a></h3><p>In <code>composeTargets</code> (<code>scripts/generate-registry.ts:133–161</code>), replace the <code>minimal</code> <code>process.exit(1)</code> with a real target:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MINIMAL_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> join</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ROOT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;runtime&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;app&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;(minimal)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// …</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (shell </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;minimal&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">join</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MINIMAL_DIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, routeSegment)];</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><strong>Multi-segment <code>routePrefix</code> is allowed for minimal</strong> (unlike <code>overlay</code>, whose single-segment rule exists only for <code>(.)</code> interception). <code>mkdirSync(dirname(dest))</code> already handles nested segments.</li><li>Extend <code>composePlugins</code>&#39; clear step (<code>:163–179</code>) to also clear the <code>(minimal)</code> group between runs, keeping its committed <code>layout.tsx</code> + <code>.gitignore</code> (a <code>MINIMAL_DIR_KEEP</code> set, analogous to <code>PLUGINS_DIR_KEEP</code>).</li></ul><h3 id="root-plugin-eligibility" tabindex="-1">Root-plugin eligibility <a class="header-anchor" href="#root-plugin-eligibility" aria-label="Permalink to &quot;Root-plugin eligibility&quot;">​</a></h3><p>Keep <code>minimal</code> <strong>eligible</strong> as the root plugin (<code>runtime/src/root-plugin.ts</code>) — a single-app / kiosk instance that serves a full-screen plugin at <code>/</code> is a legitimate operator choice, and <code>/</code>-rewrite-to-<code>routePrefix</code> already works for it. <strong>Caveat (documented):</strong> a minimal root plugin renders no chrome, so the instance has <strong>no platform navigation</strong> to reach other plugins / Console / Account — the operator opts into that deliberately. Whether to warn in Console when selecting a minimal root is an open question.</p><h3 id="navigation-contract" tabindex="-1">Navigation contract <a class="header-anchor" href="#navigation-contract" aria-label="Permalink to &quot;Navigation contract&quot;">​</a></h3><p>Minimal = &quot;the plugin dictates the entire view,&quot; so the <strong>plugin owns its own navigation</strong>, including a way back to the rest of the platform. The platform does <strong>not</strong> inject an escape hatch (that would contradict chrome-free). Convention (documented in <code>docs/plugin-development.md</code>): a minimal plugin <strong>should</strong> provide a link to <code>/</code> (or another route) so a user isn&#39;t trapped. Minimal plugins are otherwise ordinary non-chrome plugins, so they still appear in the launcher grid and the desktop sidebar / mobile Drawer (RFC 0013) — that is how a user reaches them from the default shell; activating one swaps the <code>(platform)</code> layout out for the full-bleed <code>(minimal)</code> route.</p><h3 id="manifest-validation" tabindex="-1">Manifest &amp; validation <a class="header-anchor" href="#manifest-validation" aria-label="Permalink to &quot;Manifest &amp; validation&quot;">​</a></h3><p>No schema change is required (<code>shell</code> already includes <code>minimal</code>). Remove the &quot;not supported&quot; expectation from any test that asserts the build-fail, and add coverage that a <code>minimal</code> plugin composes to <code>(minimal)/&lt;segment&gt;</code> and <strong>not</strong> into <code>(platform)</code>. <code>shellConfig.overlaySize</code> remains overlay-only (the existing <code>.refine</code>, <code>packages/manifest/src/schema.ts:67–70</code>).</p><h2 id="ui-navigation-flows" tabindex="-1">UI / navigation flows <a class="header-anchor" href="#ui-navigation-flows" aria-label="Permalink to &quot;UI / navigation flows&quot;">​</a></h2><p><strong>Open a minimal plugin from the shell</strong> — default shell → launcher grid or sidebar / mobile Drawer → tap the plugin → route changes to its <code>routePrefix</code>; the <code>(platform)</code> shell unmounts and the plugin renders full-bleed across <code>100dvh</code> (safe-area respected). The plugin&#39;s own UI provides any &quot;back to home&quot; affordance.</p><p><strong>Minimal as root (kiosk)</strong> — operator sets a minimal plugin as the root plugin → <code>/</code> rewrites to its <code>routePrefix</code> → every sign-in lands directly in the full-screen plugin with no chrome. (Operator-acknowledged: no platform nav.)</p><p><strong>Hard load / deep link</strong> — a direct hit on <code>/editor</code> is session-gated by the middleware (redirect to <code>/login</code> if unauthenticated), then renders via the <code>(minimal)</code> layout — identical gating to any other plugin route.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Nest <code>minimal</code> under <code>(platform)</code> and hide chrome with CSS.</strong> Rejected — the shell layout still mounts (and runs its <code>headers()</code>/registry work); hiding it is fragile and wastes a layout. A sibling group is the clean App-Router idiom.</li><li><strong>A single shared group with conditional chrome in one layout.</strong> Rejected — pushes per-request branching into a layout, the opposite of the composition-decides-layout model RFC 0001 established.</li><li><strong>Forbid minimal as a root plugin.</strong> Tempting (avoids a nav-less instance), but it removes the legitimate kiosk/single-app use case. Kept eligible with a documented caveat instead.</li><li><strong>Platform-injected &quot;exit&quot; button on minimal routes.</strong> Contradicts &quot;plugin owns the entire view&quot;; left to a plugin convention instead.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Console warning</strong> when an admin selects a <code>minimal</code> plugin as the root (no-chrome / no-nav consequence) — surface a confirmation, or document only?</li><li><strong>Reference plugin.</strong> Should Plainwrite (the writing surface) be the first <code>minimal</code> plugin and the worked example in the docs?</li><li><strong>Minimal × <code>adminOnly</code>.</strong> Works via <code>decidePluginRoute</code>, but is an admin-only full-screen plugin a real use case worth an example?</li><li><strong>Requirement IDs.</strong> Proposed PLT-/CON- entries (minimal route group + root-eligibility caveat) — not assigned in the SRS until accepted.</li><li><strong>Interaction with RFC 0013&#39;s safe-area guarantees</strong> — confirm the <code>(minimal)</code> layout is the single place those guarantees are applied for chrome-free routes.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong> Wiring design captured; no code, no SRS edits, no scheduling.</li><li><strong>When accepted &amp; scheduled</strong> (a small runtime + generate-script change): add the <code>(minimal)</code> group (committed <code>layout.tsx</code> + <code>.gitignore</code>), replace the generate-script build-fail with the <code>minimal</code> compose target + clear step, confirm root-plugin eligibility + the nav caveat, add compose/parity tests, and document <code>minimal</code> fully in <code>docs/plugin-development.md</code> + the CLAUDE.md load-bearing notes. Honour RFC 0013&#39;s responsive expectations in the layout.</li><li><strong>Follow-on (optional):</strong> ship a reference <code>minimal</code> plugin (candidate: Plainwrite) as the worked example.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; wire <code>shell: &quot;minimal&quot;</code> via a sibling <code>(minimal)</code> route group, generate-script branch, root eligibility + nav contract; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.5.25.</td></tr></tbody></table>',40)])])}const m=o(n,[["render",s]]);export{g as __pageData,m as default};
